mapper.select:
select

from TBL_USER_OPT_LOG lg
LEFT JOIN TBL_USER  us  ON lg.user_id=us.user_id
where 1=1


        and us.USER_NAME like '%${logReqParam.userName}%'


        and OPERATION_TYPE = #{logReqParam.operationType}


        and INTERVIEWT_TIME >= #{logReqParam.beginDate}


        and INTERVIEWT_TIME <= #{logReqParam.endDate}
